  const raw = it.json.ready_for_concept;

  const v = String(raw ?? '')
    .trim()
    .toLowerCase();

  return [
    'true',
    '1',
    'ja',
    'yes',
    'y',
    'ready',
    'passed',
    'bereit',
    'nein'
