const leadId = $json.lead_id;
const warnings = [];

// ---- Quellen laden (Sheet-Daten via Assemble Sources) ----
// $json enthÃĪlt: ...VALIDATION-Row, _lead (LEADS Sheet), _content (CONTENT Sheet)
const sheetLead    = $json._lead    || {};
const sheetContent = $json._content || {};

function splitPipe(s) {
  return String(s||'').split('|').map(x=>x.trim()).filter(Boolean);
}

