  if (!sheetLead.name) warnings.push('source_missing_lead');
} catch(e) { warnings.push('source_missing_lead'); }

// a2: Extrahierte Inhalte aus CONTENT Sheet
try {
  if (!sheetContent.lead_id) throw new Error('no content row');
  a2 = {
    fakten: {
