    stimmung: ['dunkel','edel','moody','exklusiv'],
    colors: { primary:'#C9A84C', secondary:'#1A1A1A', accent:'#8B0000',
               background:'#0D0D0D', surface:'#1A1A1A', text:'#F5F5F0', text_muted:'#A0A0A0' },
