    trigger: s => /gasthaus|gasthof|deutsch|bayerisch|thÃžring|sÃĪchsisch|schnitzel|bratwurst/i.test(s),
    stimmung: ['bodenstÃĪndig','warm','traditionell','gemÃžtlich'],
    colors: { primary:'#8B4513', secondary:'#FFF8DC', accent:'#228B22',
